SELECT DATE(taken_time)
FROM photo
WHERE user_id = #{userId}
  AND status = #{status}
  AND deleted = 0
GROUP BY DATE(taken_time)
ORDER BY DATE(taken_time) DESC
LIMIT #{offset}, #{pageSize}

SELECT COUNT(1)
FROM (
    SELECT DATE(taken_time)
    FROM photo
    WHERE user_id = #{userId}
      AND status = #{status}
      AND deleted = 0
    GROUP BY DATE(taken_time)
) taken_date_group

SELECT *
FROM photo
WHERE user_id = #{userId}
  AND status = #{status}
  AND deleted = 0
  AND DATE(taken_time) IN

      #{takenDate}

ORDER BY DATE(taken_time) DESC, taken_time DESC, upload_time DESC
